-- calc_workflows_count_of_steps
-- Field: Workflows.CountOfSteps
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_workflows_count_of_steps(p_workflow_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM workflow_steps WHERE workflow = (SELECT NULLIF(workflow_id, '') FROM workflows WHERE workflow_id = p_workflow_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_workflows_has_more_than1_step
-- Field: Workflows.HasMoreThan1Step
-- Type: calculated | DataType: boolean | Returns: BOOLEAN

CREATE OR REPLACE FUNCTION calc_workflows_has_more_than1_step(p_workflow_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_workflows_count_of_steps(p_workflow_id))::NUMERIC > 1)::boolean;
$$ LANGUAGE sql STABLE;

