-- calc_workflow_steps_execution_actor_type
-- Field: WorkflowSteps.ExecutionActorType
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_workflow_steps_execution_actor_type(p_workflow_step_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_workflow_steps_assigned_role_department(p_workflow_step_id) = 'HumanAgent' THEN ('HumanAgent')::text ELSE (CASE WHEN calc_workflow_steps_assigned_role_department(p_workflow_step_id) = 'AIAgent' THEN ('AIAgent')::text ELSE (CASE WHEN calc_workflow_steps_assigned_role_department(p_workflow_step_id) = 'AutomatedPipeline' THEN ('AutomatedPipeline')::text ELSE (NULL)::text END)::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

