-- calc_workflows_workflow_steps
-- Field: Workflows.WorkflowSteps
-- Type: Many-side relationship (backref) to WorkflowSteps
-- Aggregates: WorkflowSteps.WorkflowStepId where Workflow = parent

CREATE OR REPLACE FUNCTION calc_workflows_workflow_steps(p_workflow_id TEXT)
RETURNS TEXT AS $$
  SELECT (
    SELECT STRING_AGG(workflow_step_id::TEXT, ', ' ORDER BY workflow_step_id)
    FROM workflow_steps
    WHERE workflow = p_workflow_id
  );
$$ LANGUAGE sql STABLE;

-- calc_approvals_workflow_steps
-- Field: Approvals.WorkflowSteps
-- Type: Many-side relationship (backref) to WorkflowSteps
-- Aggregates: WorkflowSteps.WorkflowStepId where ApprovalGate = parent

CREATE OR REPLACE FUNCTION calc_approvals_workflow_steps(p_approval_id TEXT)
RETURNS TEXT AS $$
  SELECT (
    SELECT STRING_AGG(workflow_step_id::TEXT, ', ' ORDER BY workflow_step_id)
    FROM workflow_steps
    WHERE approval_gate = p_approval_id
  );
$$ LANGUAGE sql STABLE;

-- calc_roles_workflow_steps
-- Field: Roles.WorkflowSteps
-- Type: Many-side relationship (backref) to WorkflowSteps
-- Aggregates: WorkflowSteps.WorkflowStepId where AssignedRole = parent

CREATE OR REPLACE FUNCTION calc_roles_workflow_steps(p_role_id TEXT)
RETURNS TEXT AS $$
